import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.B3IQijK_.js";const u=JSON.parse('{"title":"Portfolio Manager","description":"Portfolio-level decisions across multiple brokers — weights, concentration, correlation, rebalancing, tax harvesting.","frontmatter":{"title":"Portfolio Manager","description":"Portfolio-level decisions across multiple brokers — weights, concentration, correlation, rebalancing, tax harvesting.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/guides/portfolio-manager"}]]},"headers":[],"relativePath":"guides/portfolio-manager.md","filePath":"guides/portfolio-manager.md"}'),s={name:"guides/portfolio-manager.md"};function i(n,t,l,d,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="portfolio-manager" tabindex="-1">Portfolio Manager <a class="header-anchor" href="#portfolio-manager" aria-label="Permalink to &quot;Portfolio Manager&quot;">​</a></h1><p>The meta-persona: portfolio-level decisions across <strong>multiple brokers at once</strong>. Portfolio Manager thinks in weights, sectors, cash, concentration, drawdown, and correlation before it thinks about any single ticker.</p><h2 id="what-it-s-for" tabindex="-1">What it&#39;s for <a class="header-anchor" href="#what-it-s-for" aria-label="Permalink to &quot;What it&#39;s for&quot;">​</a></h2><ul><li>Snapshots across Groww + Kite in one view</li><li>Allocation review and rebalancing plans</li><li>Position review with decision categories (keep / trim / add / exit / watch)</li><li>Tax harvesting, earnings checks, results calendar prep, IPO tracking</li><li>New-buy checklists that include portfolio-fit checks</li><li>Mutual fund review, sector analysis, market overview, and dip checks</li></ul><h2 id="primary-tools" tabindex="-1">Primary tools <a class="header-anchor" href="#primary-tools" aria-label="Permalink to &quot;Primary tools&quot;">​</a></h2><ul><li>Broker MCPs (Groww, Kite) for live holdings, positions, margins</li><li>XLSX import for portfolios held elsewhere</li><li>Browser for broker UI actions a skill walks through</li></ul><p>Portfolio Manager starts from the portfolio question, not the ticker question. If context is missing, it asks for the minimum useful details: holdings, weights, cash, horizon, and constraints.</p><h2 id="core-workflows" tabindex="-1">Core workflows <a class="header-anchor" href="#core-workflows" aria-label="Permalink to &quot;Core workflows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Workflow</th><th>Use it for</th></tr></thead><tbody><tr><td>Snapshot</td><td>Unified view of holdings, positions, cash, P&amp;L, weights, and broker attribution</td></tr><tr><td>Allocation Review</td><td>Concentration, cash deployment, broker split, and portfolio drift</td></tr><tr><td>Rebalancing Plan</td><td>Trim/add/watch plan based on current allocation and target constraints</td></tr><tr><td>Position Review</td><td>Existing holding review across brokers with keep/trim/add/exit/watch framing</td></tr><tr><td>New Buy Checklist</td><td>Test whether a new stock fits the portfolio before starting a position</td></tr><tr><td>Tax Harvesting</td><td>Cross-broker tax-loss and gain review using broker reports</td></tr><tr><td>Earnings Check</td><td>Latest visible earnings summary for a specific stock</td></tr><tr><td>Results Calendar Prep</td><td>Watchlist of portfolio holdings that matter most into earnings season</td></tr><tr><td>Mutual Fund Review</td><td>Cross-broker MF holdings, SIPs, overlap, allocation, and concentration</td></tr><tr><td>IPO Tracker</td><td>Upcoming, open, and recently closed IPOs through connected brokers</td></tr><tr><td>Market Overview</td><td>Daily market pulse, index levels, movers, volume shockers, and trending names</td></tr><tr><td>Sector Analysis</td><td>Sector heatmap, top/bottom sectors, and top stocks by sector</td></tr><tr><td>Dip Check</td><td>Decide whether a stock fall is noise, caution, or an add/watch opportunity</td></tr><tr><td>Stock Analysis</td><td>Broker-backed stock analysis when a single-name view is needed</td></tr></tbody></table><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p>Before first use, pick which brokers you want unified with <code>Ctrl+Shift+K</code> or <code>/brokers</code>. Portfolio Manager only shows actions for selected brokers.</p><p>If both Groww and Kite are configured, Portfolio Manager can merge broker views into one portfolio picture. If one broker fails or is not logged in, it should continue with the available broker and clearly mark the result as partial.</p><h2 id="typical-prompts" tabindex="-1">Typical prompts <a class="header-anchor" href="#typical-prompts" aria-label="Permalink to &quot;Typical prompts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Show my portfolio</span></span>
<span class="line"><span>Allocation review — am I overweight anywhere?</span></span>
<span class="line"><span>Rebalance plan for my target 60% equity / 30% debt / 10% cash</span></span>
<span class="line"><span>Tax harvesting ideas for FY26</span></span>
<span class="line"><span>New buy checklist for BAJFINANCE</span></span>
<span class="line"><span>Which of my holdings have results next week?</span></span>
<span class="line"><span>Review my mutual funds across brokers</span></span>
<span class="line"><span>Is this dip in HDFCBANK a chance to add or a thesis break?</span></span>
<span class="line"><span>Show market overview and sector leaders today</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Read-only by default</p><p>Portfolio Manager surfaces decisions but does not execute orders automatically. It must not fabricate holdings, allocation weights, prices, cash balances, or broker confirmations. Any action that moves money requires explicit user authorization at the broker, and claims of &quot;deployed&quot;, &quot;placed&quot;, or &quot;rebalanced&quot; only appear when a tool confirms execution.</p></div><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><strong>Compare with other personas</strong> → <a href="/trading-sandbox-website-preview/wiki/guides/personas">Personas &amp; Modes</a></li><li><strong>Connect brokers</strong> → <a href="./../getting-started/broker-setup">Broker Setup</a> — Groww and Zerodha Kite OAuth flows</li></ul>`,17)])])}const f=e(s,[["render",i]]);export{u as __pageData,f as default};
